%[text] # R04: タンパク質-リガンド解析 — 構造ベースリガンドプロファイリング
%[text] EasyMolKit Research — Layer 4
%[text] 
%[text] ドラッグリポジショニング（drug repositioning）とは、既に別の疾患で承認された薬が新しいターゲットにも効くかを探索する戦略です。
%[text] 3D ドッキングシミュレーターを使わず、分子フィンガープリントと物理化学プロファイルだけで候補を絞り込める手法がリガンドベース仮想スクリーニング（LBVS: Ligand-Based Virtual Screening）です。
%[text] このスクリプトでは 5 種類の承認済みキナーゼ阻害剤を参照に、FDA 薬物 200 件を LBVS でスコアリングし、有望なリポジショニング候補を特定してレポートに出力します。
%[text] 
%[text] **スコープの注意** 
%[text] 実際の分子ドッキング（AutoDock、Glide 等）はこの演習では行いません。代わりに、2D フィンガープリント類似度・物理化学的プロパティマッチ・Bioinformatics Toolbox によるシーケンスアライメントを組み合わせた LBVS ワークフローを実装します。
%[text] **学習目標**
%[text] - LBVS の原理と構造ベースドッキングとの違いを理解する
%[text] - RDKit 記述子で承認済みキナーゼ阻害剤の化学空間をプロファイルする
%[text] - 多基準スコアリング関数を設計・実装する
%[text] - MATLAB Bioinformatics Toolbox でタンパク質配列を解析する
%[text] - リガンド効率（ligand efficiency）と生の活性指標の違いを理解する \
%[text] **前提条件**
%[text] - Bioinformatics Toolbox
%[text] - Biopython：`emk.setup.installExtra("biopython")` を初回のみ実行してください \
%[text] **データ**
%[text] - `data/list/fda_drugs.csv` — FDA 承認薬 200 件（ChEMBL、CC-BY-SA 3.0）
%[text] - 参照キナーゼ阻害剤の SMILES は Section 1 に埋め込まれています。
%[text] - PKA 触媒サブユニット FASTA（UniProt P17612）は Section 4 に埋め込まれています。 \
%[text] **参考文献**
%[text] - Bleicher KH et al. (2003) Nat Rev Drug Discov 2:369-378. — LBVS と多基準スコアリング
%[text] - Lipinski CA et al. (2001) Adv Drug Deliv Rev 46:3-26. — Ro5 と薬物様性
%[text] - Hopkins AL & Groom CR (2002) Nat Rev Drug Discov 1:727-730. — リガンド効率の概念
%[text] - Rogers D & Hahn M (2010) J Chem Inf Model 50:742-754. — ECFP4 フィンガープリント
%[text] - Cock PJA et al. (2009) Bioinformatics 25:1422-1423. — Biopython \
%[text] 所要時間: 45〜90 分 | 実行方法：Ctrl+Enter でセクションごとに実行します。
%%
%[text] ## Section 0: セットアップ
% Resolve project root (works for Desktop, MCP, and MATLAB Online)
sDir = fileparts(mfilename('fullpath'));
if strlength(sDir) > 0
    addpath(genpath(fullfile(sDir, '..', '..', '..', 'src')));
elseif isfolder(fullfile(pwd, 'src'))
    addpath(genpath(fullfile(pwd, 'src')));
elseif ~isempty(which("logInfo"))
    addpath(genpath(fileparts(fileparts(which("logInfo")))));
end
projectRoot = resolveProjectRoot();
addpath(genpath(fullfile(projectRoot, 'src')));
emk.setup.initPython(); %[output:2e78f9d0]
%[text] Python/RDKit プロセスをウォームアップします。
mol_warmup = emk.mol.fromSmiles("C");
clear mol_warmup;
%[text] Bioinformatics Toolbox の有無を確認します。
hasBioTbx = license("test", "bioinformatics_toolbox");
if hasBioTbx %[output:group:25fac20a]
    logInfo("R04: Bioinformatics Toolbox を検出しました。"); %[output:86ea0a0d]
else
    logWarn("R04: Bioinformatics Toolbox が見つかりません。Section 4 は手動フォールバックを使用します。");
end %[output:group:25fac20a]
%[text] Biopython の有無を確認します。
bpAvailable = false;
try %[output:group:3b4180f6]
    py.importlib.import_module("Bio");
    bpAvailable = true;
    logInfo("R04: Biopython を検出しました。"); %[output:1853dabb]
catch
    logWarn("R04: Biopython が見つかりません。emk.setup.installExtra(""biopython"") を実行してください。");
end %[output:group:3b4180f6]
logInfo("R04: セットアップ完了。"); %[output:9c021d05]
%%
%[text] ## Section 1: キナーゼ阻害剤化学空間のプロファイリング
%[text] ### **リガンドベース仮想スクリーニング（LBVS）の原理**
%[text] 構造ベースドッキングには 3D タンパク質構造とドッキングソフトウェアが必要です。
%[text] それらが利用できない場合に使う代替手法が LBVS であり、「類似する分子は類似する生物活性を持つ傾向がある」という類似性-プロパティ原理（Johnson & Maggiora 1990）が理論的根拠です。
%[text] LBVS の手順は次の 3 ステップです
%[text] 1. 既知の活性リガンド（参照阻害剤）を選ぶ
%[text] 2. すべての候補と参照の構造類似度を計算する
%[text] 3. 類似度でランキングして高類似度候補を優先する \
%[text] このセクションでは、以下の 5 種類の承認済みキナーゼ阻害剤の物理化学的フットプリントを計算し、スクリーニングの参照空間を定義します。
%[text:table]{"ignoreHeader":true}
%[text] | 薬剤名 | ターゲット | 阻害剤クラス |
%[text] | --- | --- | --- |
%[text] | イマチニブ | BCR-ABL / c-KIT / PDGFR | 第一世代 TKI |
%[text] | エルロチニブ | EGFR | EGFR 阻害剤 |
%[text] | ゲフィチニブ | EGFR | EGFR 阻害剤 |
%[text] | ダサチニブ | BCR-ABL / Src | マルチキナーゼ阻害剤 |
%[text] | ソラフェニブ | RAF / VEGFR / PDGFR | マルチキナーゼ阻害剤 |
%[text:table]
%[text] 
%[text] これら 5 薬剤は Type I / II / III 結合モードにまたがる多様なキナーゼ阻害剤を代表しており、LBVS クエリとして使用します。
REF_NAMES  = ["Imatinib", "Erlotinib", "Gefitinib", "Dasatinib", "Sorafenib"];
REF_SMILES = [ ...
    "Cc1ccc(cc1Nc2nccc(n2)c3cccnc3)NC(=O)c4ccc(cc4)CN5CCN(CC5)C", ...  % Imatinib
    "C#Cc1cccc(c1)Nc2ncnc3cc(OCCOC)c(OCCOC)cc23",                       ...  % Erlotinib
    "COc1cc2ncnc(Nc3ccc(F)c(Cl)c3)c2cc1OCCCN4CCOCC4",                  ...  % Gefitinib
    "Cc1nc(Nc2ncc(s2)C(=O)Nc3c(C)cccc3Cl)cc(n1)N4CCN(CCO)CC4",        ...  % Dasatinib
    "CNC(=O)c1cc(ccn1)Oc2ccc(cc2)NC(=O)Nc3ccc(c(c3)C(F)(F)F)Cl"       ...  % Sorafenib
    ];
FP_RADIUS = 2;
FP_NBITS  = 2048;
%[text] 参照阻害剤をパースし、記述子とフィンガープリントを計算します。
nRef      = numel(REF_NAMES);
refMols   = cell(1, nRef);
refFps    = cell(1, nRef);
refValid  = false(1, nRef);
for k = 1:nRef
    try
        refMols{k}  = emk.mol.fromSmiles(REF_SMILES(k));
        refFps{k}   = emk.fingerprint.morgan(refMols{k}, Radius=FP_RADIUS, NBits=FP_NBITS);
        refValid(k) = true;
    catch ex
        logWarn("R04: %s をパースできませんでした: %s", REF_NAMES(k), ex.message);
    end
end
validRef  = find(refValid);
refMols   = refMols(validRef);
refFps    = refFps(validRef);
refNames  = REF_NAMES(validRef);
nRefValid = numel(validRef);
logInfo("R04 Sec1: 参照キナーゼ阻害剤 %d / %d をパースしました。", nRefValid, nRef); %[output:478d9f99]
%[text] 参照阻害剤の物理化学的記述子を計算します。
DESCS      = ["MolWt", "LogP", "TPSA", "NumHDonors", "NumHAcceptors", "NumRotatableBonds"];
refDescTbl = emk.descriptor.batchCalculate(refMols, DESCS);
refDescTbl.Name = refNames';
logInfo("キナーゼ阻害剤の物理化学的プロファイル:"); %[output:5ea4cbac]
logInfo("  %-12s  %6s  %5s  %6s  %4s  %4s  %4s", ... %[output:group:1c857b2e] %[output:1f7aeafc]
    "Name", "MolWt", "LogP", "TPSA", "HBD", "HBA", "RotB"); %[output:group:1c857b2e] %[output:1f7aeafc]
for k = 1:height(refDescTbl) %[output:group:837ee193]
    logInfo("  %-12s  %6.1f  %5.2f  %6.1f  %4.0f  %4.0f  %4.0f", ... %[output:9f905cb5]
        refNames(k), ... %[output:9f905cb5]
        refDescTbl.MolWt(k), refDescTbl.LogP(k), refDescTbl.TPSA(k), ... %[output:9f905cb5]
        refDescTbl.NumHDonors(k), refDescTbl.NumHAcceptors(k), ... %[output:9f905cb5]
        refDescTbl.NumRotatableBonds(k)); %[output:9f905cb5]
end %[output:group:837ee193]
%[text] 後のスコアリングで使う参照 KI の中央値プロファイルを計算します。
kiMedian.MolWt             = median(refDescTbl.MolWt);
kiMedian.LogP              = median(refDescTbl.LogP);
kiMedian.TPSA              = median(refDescTbl.TPSA);
kiMedian.NumHDonors        = median(refDescTbl.NumHDonors);
kiMedian.NumHAcceptors     = median(refDescTbl.NumHAcceptors);
kiMedian.NumRotatableBonds = median(refDescTbl.NumRotatableBonds);
logInfo("参照 KI 中央値: MW=%.0f, LogP=%.2f, TPSA=%.0f", ... %[output:group:6f74f4cd] %[output:60a58f74]
    kiMedian.MolWt, kiMedian.LogP, kiMedian.TPSA); %[output:group:6f74f4cd] %[output:60a58f74]
%[text] **図の見方** 各軸はプロパティの上限値で正規化した相対値です（例：MW/600）。
%[text] 5 薬剤の線がどれだけ似た形を描くかで、化学空間の均質性を確認できます。
figure("Name", "R04 Sec1: Kinase Inhibitor Property Profile"); %[output:11ab4f49]
propMat_ref = [refDescTbl.MolWt/600, ...
               (refDescTbl.LogP + 2) / 8, ...
               refDescTbl.TPSA / 200, ...
               refDescTbl.NumHDonors / 6, ...
               refDescTbl.NumHAcceptors / 12, ...
               refDescTbl.NumRotatableBonds / 14];
axLabels = ["MW_600", "LogP_8", "TPSA_200", "HBD_6", "HBA_12", "RotB_14"];
propTbl_ref = array2table(propMat_ref, VariableNames=cellstr(axLabels));
propTbl_ref.Inhibitor = refNames';
parallelplot(propTbl_ref, GroupVariable="Inhibitor"); %[output:11ab4f49]
title("キナーゼ阻害剤 正規化プロパティプロファイル"); %[output:11ab4f49]
%%
%[text] ## Section 2: フィンガープリント類似度による FDA 薬物ライブラリスクリーニング
%[text] ### **タニモト係数（Tanimoto similarity）とは**
%[text] 分子フィンガープリントは各ビットが特定の部分構造の有無を表すビット列です。
%[text] 2 つのフィンガープリント $q$（クエリ）と $d$（データベース分子）のタニモト係数は次の式で定義されます。
%[text]{"align":"center"} $T(q, d) = \\frac{|q \\cap d|}{|q \\cup d|}$
%[text] ここで $|q \\cap d|$ は両方のフィンガープリントに立っているビット数、$|q \\cup d|$ はどちらかに立っているビット数の合計を表します。$T$ は 0（共通ビットなし）から 1（完全一致）の範囲をとり、値が大きいほど構造的に類似した分子です。
%[text] 創薬の経験則として $T \> 0.85$ の化合物は「近接類似体」とみなされますが、このスクリーニングでは 0.40 と 0.50 も参考閾値として使います。
%[text] 各 FDA 薬物について、5 種類の参照 KI すべてとの最大タニモト類似度を次のように定義します。
%[text]{"align":"center"} $\\text{maxSim}(c) = \\max \\{ T(c,\\, r(k)) \\mid k = 1, \\ldots, K \\}$
%[text] $r(k)$ は $k$ 番目の参照 KI のフィンガープリントです。
%[text] この値が高いほど、候補分子がいずれかの既知 KI と化学空間上で近い位置にあることを意味します。
DATA_FILE = "data/list/fda_drugs.csv";
rawTbl    = readtable(DATA_FILE, TextType="string");
logInfo("R04 Sec2: %s から %d 件を読み込みました。", DATA_FILE, height(rawTbl)); %[output:88a38408]
nLib  = height(rawTbl);
mols  = cell(1, nLib);
fps   = cell(1, nLib);
valid = false(1, nLib);
for k = 1:nLib %[output:group:3330efbc]
    try
        mols{k}  = emk.mol.fromSmiles(rawTbl.SMILES(k));
        fps{k}   = emk.fingerprint.morgan(mols{k}, Radius=FP_RADIUS, NBits=FP_NBITS);
        valid(k) = true;
    catch
        % skip unparseable entries silently
    end
    if mod(k, 20) == 0 || k == nLib
        logProgress(k, nLib, "FDA ライブラリのフィンガープリント化"); %[output:72e5c800]
    end
end %[output:group:3330efbc]
validIdx  = find(valid);
mols      = mols(validIdx);
fps       = fps(validIdx);
libNames  = rawTbl.Name(validIdx);
libSmiles = rawTbl.SMILES(validIdx);
nValid    = numel(validIdx);
logInfo("R04 Sec2: 分子 %d / %d をパースしました。", nValid, nLib); %[output:3e6354db]
%[text] `emk.similarity.rankBy` を使い、参照 KI ごとに全ライブラリとの類似度を計算します。
maxSimScores = zeros(nValid, 1);
simMatrix    = zeros(nValid, nRefValid);
for r = 1:nRefValid
    result = emk.similarity.rankBy(refFps{r}, fps, Inf, Metric="tanimoto");
    simMatrix(result.Indices, r) = result.Scores;
end
maxSimScores = max(simMatrix, [], 2);
bestRefIdx   = zeros(nValid, 1);
for k = 1:nValid
    [~, bestRefIdx(k)] = max(simMatrix(k, :));
end
bestRefName  = refNames(bestRefIdx)';
logInfo("R04 Sec2: 最大類似度の分布:"); %[output:96b9226d]
logInfo("  > 0.70（近接類似体）         : %d", sum(maxSimScores > 0.70)); %[output:7f83905b]
logInfo("  > 0.50（近傍分子）           : %d", sum(maxSimScores > 0.50)); %[output:217d34b7]
logInfo("  > 0.40（同系スキャフォールド）: %d", sum(maxSimScores > 0.40)); %[output:230ce3ef]
%[text] **図の見方** ヒストグラムの右裾に分布する薬物が KI 化学空間に近い候補です。
figure("Name", "R04 Sec2: Max Tanimoto Similarity to Kinase Inhibitors"); %[output:66021ae6]
histogram(maxSimScores, 30, FaceColor=[0.2 0.5 0.8], FaceAlpha=0.7); %[output:66021ae6]
xline(0.40, "r--", "LineWidth", 1.5, DisplayName="0.40 閾値"); %[output:66021ae6]
xline(0.50, "g--", "LineWidth", 1.5, DisplayName="0.50 閾値"); %[output:66021ae6]
xlabel("参照 KI への最大タニモト類似度"); %[output:66021ae6]
ylabel("化合物数"); %[output:66021ae6]
title("FDA 薬物 vs キナーゼ阻害剤化学空間"); %[output:66021ae6]
legend(Location="best"); %[output:66021ae6]
%[text] **注** FDA ライブラリにはエルロチニブ（遊離塩基形）が含まれており、参照セットと同一の SMILES です。
%[text] そのため、タニモト係数は 1.0（完全一致）になります。
%[text] これは既知の EGFR 阻害剤が上位ヒットとして正しく検出されるか確認するためのポジティブコントロールとして機能します。
%%
%[text] ## Section 3: 複合キナーゼ-リガンドスコアリング
%[text] ### **多基準スコアリング関数の設計**
%[text] タニモト類似度だけでは ADMET プロパティを無視するため、薬候補の優先順位付けには不十分です。このセクションでは、3 つの直交するシグナルを組み合わせた複合スコアを構築します。
%[text] 
%[text] **成分 1：構造類似度スコア** $S(\\text{sim})$**（重み 0.4）**
%[text] 候補が既知 KI に構造的に似ているかを捉えるシグナルです。
%[text] Section 2 で計算した $\\text{maxSim}$ をそのまま使います（値域 $\[0, 1\]$）。
%[text] 活性クラス帰属の予測性が最も高いシグナルなので、最大の重みを与えます。
%[text] 
%[text] **成分 2：物理化学的プロパティマッチスコア** $S(\\text{prop})$**（重み 0.4）**
%[text] 候補の MW・LogP・TPSA が参照 KI 群の中央値プロファイルにどれだけ近いかをガウス関数で評価します。
%[text] プロパティ値 $x$、参照中央値 $\\bar{x}$、幅パラメータ $\\sigma$ に対して $g(x) = \\exp\\!\\left( -\\frac{(x - \\bar{x})^2}{2\\sigma^2} \\right)$ と定義し、3 プロパティの平均を $S(\\text{prop})$ とします。
%[text] キナーゼ阻害剤の典型的なプロパティ範囲は MW 400-550 g/mol、LogP 2.0-4.5、TPSA 60-140 Å² です。
%[text] これは古典的な Ro5（Lipinski の Rule of Five）の範囲より広く、キナーゼ阻害剤が「bRo5（beyond Ro5）」と呼ばれる理由の一つです。
%[text] 
%[text] **成分 3：リガンド効率代理指標 LE（重み 0.2）**
%[text] リガンド効率（ligand efficiency）は重原子 1 個あたりの効力であり、分子が大きくなっても活性が向上しているかを測る指標です。実測 IC50 がない場合は、Hopkins et al.（2004）に基づく物理化学的代理指標を使います。
%[text]{"align":"center"} $\\text{LE} = \\frac{\\exp( -|\\text{LogP} - 3.0| / 2 )}{\\text{MW} / 300}$
%[text] 分子の LogP が 3.0（透過性と溶解度のバランスが最適な目安）に近く、かつ MW が小さいほど LE の値が高くなります。理想的な効率的リガンド（MW = 300、LogP = 3.0）では $\\text{LE} \\to 1.0$ になります。
%[text] 
%[text] **複合スコア式**
%[text]{"align":"center"} $\\text{Score} = 0.4 \\times S(\\text{sim}) + 0.4 \\times S(\\text{prop}) + 0.2 \\times \\text{LE}$
%[text] 3 成分はすべて $\[0, 1\]$ に正規化されているため、重みの和（1.0）がそのまま最大スコアになります。
libDescTbl = emk.descriptor.batchCalculate(mols, DESCS);
S_sim = maxSimScores;
%[text] ガウス幅 $\\sigma$ は承認済み KI の化学空間の広がりから設定します（MW: 80 g/mol、LogP: 1.5、TPSA: 40 Å²）。
sigma_MW   = 80.0;
sigma_LogP = 1.5;
sigma_TPSA = 40.0;
gMW   = exp(-0.5 * ((libDescTbl.MolWt  - kiMedian.MolWt)  / sigma_MW)  .^2);
gLogP = exp(-0.5 * ((libDescTbl.LogP   - kiMedian.LogP)   / sigma_LogP).^2);
gTPSA = exp(-0.5 * ((libDescTbl.TPSA   - kiMedian.TPSA)   / sigma_TPSA).^2);
S_prop = (gMW + gLogP + gTPSA) / 3;
%[text] MW が極小値になるのを防ぐためクランプ処理を行います（FDA データでは通常不要）。
mw_safe  = max(libDescTbl.MolWt, 50);
LE_proxy = exp(-abs(libDescTbl.LogP - 3.0) / 2) ./ (mw_safe / 300);
LE_proxy = min(LE_proxy, 1.0);
LE_proxy = max(LE_proxy, 0.0);
W_SIM  = 0.4;
W_PROP = 0.4;
W_LE   = 0.2;
compositeScore = W_SIM * S_sim + W_PROP * S_prop + W_LE * LE_proxy;
%[text] 結果テーブルを複合スコア降順にソートします。
resultTbl = table(libNames, libSmiles, maxSimScores, bestRefName, ...
    libDescTbl.MolWt, libDescTbl.LogP, libDescTbl.TPSA, ...
    libDescTbl.NumHDonors, libDescTbl.NumHAcceptors, ...
    S_sim, S_prop, LE_proxy, compositeScore, ...
    VariableNames=["Name", "SMILES", "MaxSim", "BestRefKI", ...
        "MolWt", "LogP", "TPSA", "HBD", "HBA", ...
        "Score_Sim", "Score_Prop", "Score_LE", "CompositeScore"]);
resultTbl = sortrows(resultTbl, "CompositeScore", "descend");
logInfo("R04 Sec3: 上位 10 件のキナーゼ-リガンド候補:"); %[output:97e210fc]
logInfo("  %-20s  %5s  %5s  %5s  %5s  %5s  %7s", ... %[output:group:7649690e] %[output:632047ca]
    "Name", "MW", "LogP", "TPSA", "Sim", "Prop", "Total"); %[output:group:7649690e] %[output:632047ca]
for k = 1:min(10, height(resultTbl)) %[output:group:0253fb14]
    logInfo("  %-20s  %5.0f  %5.2f  %5.0f  %5.3f  %5.3f  %7.4f", ... %[output:62dbfae3]
        resultTbl.Name(k), resultTbl.MolWt(k), resultTbl.LogP(k), ... %[output:62dbfae3]
        resultTbl.TPSA(k), resultTbl.Score_Sim(k), resultTbl.Score_Prop(k), ... %[output:62dbfae3]
        resultTbl.CompositeScore(k)); %[output:62dbfae3]
end %[output:group:0253fb14]
%[text] **図の見方** 積み上げ棒グラフの各色は成分スコアの寄与を示します（青：類似度、橙：プロパティマッチ、緑：LE 代理指標）。
top20 = resultTbl(1:min(20, height(resultTbl)), :);
figure("Name", "R04 Sec3: Composite Score Decomposition -- Top 20"); %[output:7eec60ee]
set(gcf, "Position", [100, 100, 900, 420]); %[output:7eec60ee]
barData = [top20.Score_Sim, top20.Score_Prop, top20.Score_LE];
b = bar(barData, "stacked"); %[output:7eec60ee]
b(1).FaceColor = [0.2 0.5 0.8]; %[output:7eec60ee]
b(2).FaceColor = [0.8 0.4 0.2]; %[output:7eec60ee]
b(3).FaceColor = [0.3 0.7 0.3]; %[output:7eec60ee]
xticks(1:height(top20)); %[output:7eec60ee]
xticklabels(top20.Name); %[output:7eec60ee]
xtickangle(45); %[output:7eec60ee]
ylabel("スコア成分（生値・重み未反映）"); %[output:7eec60ee]
title("キナーゼ-リガンド複合スコア — 上位 20 FDA 薬物"); %[output:7eec60ee]
legend(["類似度 (w=0.4)", "プロパティマッチ (w=0.4)", "LE 代理指標 (w=0.2)"], ... %[output:group:9aee7da9] %[output:7eec60ee]
    Location="northeast"); %[output:group:9aee7da9] %[output:7eec60ee]
%[text] 散布図で類似度スコアとプロパティマッチスコアの相関を確認します。
%[text] 右上に位置する化合物（両スコアが高い）が最も有望な候補です。
figure("Name", "R04 Sec3: Similarity vs Property Match Score"); %[output:460ee698]
scatter(S_sim, S_prop, 30, compositeScore, "filled", MarkerFaceAlpha=0.6); %[output:460ee698]
cb = colorbar(); %[output:460ee698]
cb.Label.String = "複合スコア"; %[output:460ee698]
xlabel("類似度スコア S(sim)"); %[output:460ee698]
ylabel("プロパティマッチスコア S(prop)"); %[output:460ee698]
title("FDA 薬物スコアリング全景図"); %[output:460ee698]
xline(0.40, "r--", DisplayName="Sim = 0.40"); %[output:460ee698]
yline(0.40, "b--", DisplayName="Prop = 0.40"); %[output:460ee698]
legend(Location="best"); %[output:460ee698]
